        SELECT CustomerID FROM transactions_1k WHERE Year = 2013 AND Currency = 'CZK' GROUP BY CustomerID ORDER BY SUM(Amount) ASC LIMIT 1
    ) AND Date LIKE '2013%' AND Segment = 'SME') - 
    (SELECT AVG(Consumption) FROM yearmonth WHERE CustomerID IN (
        SELECT CustomerID FROM transactions_1k WHERE Year = 2013 AND Currency = 'CZK' GROUP BY CustomerID ORDER BY SUM(Amount) ASC LIMIT 1 OFFSET 1
    ) AND Date LIKE '2013%' AND Segment = 'LAM') AS diff_SME_LAM,;

SELECT SUM(cost) AS total_cost_of_pizzas
FROM expense
